import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"握击","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/肉搏类/握击.md","filePath":"4.资源分区/6.技艺及称号/武技类/肉搏类/握击.md"}'),d={name:"4.资源分区/6.技艺及称号/武技类/肉搏类/握击.md"};function p(l,a,i,_,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"握击",tabindex:"-1"},[s("握击 "),e("a",{class:"header-anchor",href:"#握击","aria-label":'Permalink to "握击"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),o('<h1 id="握击-1" tabindex="-1">握击 <a class="header-anchor" href="#握击-1" aria-label="Permalink to &quot;握击&quot;">​</a></h1><p>握击<br> B+2000</p><p>“人体的末端是有着复杂的血管脉络的，那些精密的血管隐藏在皮肤下面”<br> “理论上，如果握住末端，那血液带来的压力最后可以令皮肤破坏”<br> “不过，能做到那种事情的人，【肯定不存在吧】”<br> “在看到那家伙之前，我是这么认为的”</p><p>消耗一个标准动作进行一次肉搏攻击，这次攻击检定加骰上升一级（最高8加骰），天生武器的伤害增加【传奇力量+1】点，必须选定某一肢体，视作为特殊部位攻击，在这次攻击中忽略3点特殊部位减值，你握住对方的肢体末端，用握力压缩对方的血液，使其皮肤无法承受最后破坏，对方需以强韧豁免对抗伤害出目，并在那条肢体上受到差值的肢体残障点数，若对方的决心属性低于这次攻击检定的出目，那么对方还需要以强韧豁免对抗伤害出目，并且受到差值的剧痛异常点数。</p><p>该能力给与的异常点数皆为B级创伤来源。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
